1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>环卫云 - 项目作业监管 - 无人作业Tab</title>
7	<style>
8	  * { margin: 0; padding: 0; box-sizing: border-box; }
9	  :root {
10	    --bg-primary: #060e1a;
11	    --bg-secondary: #0a192f;
12	    --bg-card: rgba(10, 30, 60, 0.85);
13	    --bg-panel: rgba(8, 20, 45, 0.92);
14	    --border-color: rgba(64, 180, 255, 0.15);
15	    --border-light: rgba(64, 180, 255, 0.08);
16	    --accent-cyan: #00d4ff;
17	    --accent-blue: #40b4ff;
18	    --accent-green: #00e676;
19	    --accent-orange: #ff9100;
20	    --accent-red: #ff5252;
21	    --accent-purple: #b388ff;
22	    --text-primary: #e8f0fe;
23	    --text-secondary: rgba(200, 220, 255, 0.55);
24	    --text-value: #ffffff;
25	    --radius: 6px;
26	  }
27	  body {
28	    background: var(--bg-primary);
29	    color: var(--text-primary);
30	    font-family: "PingFang SC", "Microsoft YaHei", -apple-system, sans-serif;
31	    height: 100vh;
32	    overflow: hidden;
33	  }
34	
35	  /* ===== Layout ===== */
36	  .page {
37	    display: grid;
38	    grid-template-columns: 1fr 420px;
39	    grid-template-rows: 56px 1fr;
40	    height: 100vh;
41	  }
42	
43	  /* ===== Top Bar ===== */
44	  .topbar {
45	    grid-column: 1 / -1;
46	    background: var(--bg-panel);
47	    border-bottom: 1px solid var(--border-color);
48	    display: flex;
49	    align-items: center;
50	    justify-content: space-between;
51	    padding: 0 20px;
52	  }
53	  .topbar-left {
54	    display: flex;
55	    align-items: center;
56	    gap: 20px;
57	  }
58	  .topbar-breadcrumb {
59	    font-size: 13px;
60	    color: var(--text-secondary);
61	  }
62	  .topbar-breadcrumb span { color: var(--text-primary); }
63	  .topbar-project {
64	    font-size: 15px;
65	    font-weight: 600;
66	    color: var(--accent-cyan);
67	  }
68	  .topbar-right {
69	    display: flex;
70	    align-items: center;
71	    gap: 16px;
72	    font-size: 12px;
73	    color: var(--text-secondary);
74	  }
75	  .live-dot {
76	    width: 6px; height: 6px;
77	    border-radius: 50%;
78	    background: var(--accent-green);
79	    box-shadow: 0 0 6px var(--accent-green);
80	    display: inline-block;
81	    margin-right: 4px;
82	  }
83	
84	  /* ===== Tab Bar ===== */
85	  .tab-bar {
86	    display: flex;
87	    gap: 0;
88	    background: var(--bg-panel);
89	    border-bottom: 1px solid var(--border-color);
90	    padding: 0 16px;
91	  }
92	  .tab {
93	    padding: 12px 20px;
94	    font-size: 13px;
95	    color: var(--text-secondary);
96	    cursor: pointer;
97	    border-bottom: 2px solid transparent;
98	    transition: all 0.2s;
99	    display: flex;
100	    align-items: center;
101	    gap: 6px;
102	  }
103	  .tab:hover { color: var(--text-primary); }
104	  .tab.active {
105	    color: var(--accent-cyan);
106	    border-bottom-color: var(--accent-cyan);
107	  }
108	  .tab .badge {
109	    background: rgba(0, 212, 255, 0.15);
110	    color: var(--accent-cyan);
111	    padding: 1px 6px;
112	    border-radius: 10px;
113	    font-size: 10px;
114	  }
115	
116	  /* ===== Map Area ===== */
117	  .map-area {
118	    display: flex;
119	    flex-direction: column;
120	    overflow: hidden;
121	  }
122	  .map-wrapper {
123	    flex: 1;
124	    position: relative;
125	    background: radial-gradient(ellipse at center, rgba(0, 40, 80, 0.3), var(--bg-primary));
126	    overflow: hidden;
127	  }
128	
129	  /* Grid lines */
130	  .grid-overlay {
131	    position: absolute;
132	    inset: 0;
133	    pointer-events: none;
134	    z-index: 1;
135	  }
136	
137	  /* Map vehicle markers */
138	  .map-vehicle {
139	    position: absolute;
140	    z-index: 10;
141	    cursor: pointer;
142	    transition: transform 0.15s;
143	  }
144	  .map-vehicle:hover { transform: scale(1.15); z-index: 20; }
145	  .vehicle-icon {
146	    width: 36px;
147	    height: 36px;
148	    border-radius: 50%;
149	    display: flex;
150	    align-items: center;
151	    justify-content: center;
152	    font-size: 14px;
153	    font-weight: 700;
154	    border: 2px solid;
155	    position: relative;
156	  }
157	  .vehicle-icon::after {
158	    content: "";
159	    position: absolute;
160	    inset: -6px;
161	    border-radius: 50%;
162	    border: 1px solid currentColor;
163	    opacity: 0;
164	    animation: v-pulse 3s infinite;
165	  }
166	  @keyframes v-pulse {
167	    0%, 80% { opacity: 0; transform: scale(1); }
168	    85% { opacity: 0.4; }
169	    100% { opacity: 0; transform: scale(1.8); }
170	  }
171	  .vehicle-icon.running {
172	    background: rgba(0, 212, 255, 0.15);
173	    border-color: var(--accent-cyan);
174	    color: var(--accent-cyan);
175	    box-shadow: 0 0 12px rgba(0, 212, 255, 0.3);
176	  }
177	  .vehicle-icon.running::after { border-color: var(--accent-cyan); }
178	  .vehicle-icon.idle {
179	    background: rgba(0, 230, 118, 0.12);
180	    border-color: var(--accent-green);
181	    color: var(--accent-green);
182	    box-shadow: 0 0 8px rgba(0, 230, 118, 0.2);
183	  }
184	  .vehicle-icon.charging {
185	    background: rgba(255, 145, 0, 0.12);
186	    border-color: var(--accent-orange);
187	    color: var(--accent-orange);
188	  }
189	  .vehicle-icon.offline {
190	    background: rgba(120, 120, 140, 0.1);
191	    border-color: rgba(120, 120, 140, 0.4);
192	    color: rgba(120, 120, 140, 0.6);
193	  }
194	  .vehicle-label {
195	    position: absolute;
196	    top: 40px;
197	    left: 50%;
198	    transform: translateX(-50%);
199	    font-size: 10px;
200	    color: var(--text-secondary);
201	    white-space: nowrap;
202	    pointer-events: none;
203	  }
204	
205	  /* Vehicle Popup */
206	  .vehicle-popup {
207	    position: absolute;
208	    z-index: 50;
209	    background: var(--bg-panel);
210	    border: 1px solid var(--accent-cyan);
211	    border-radius: 8px;
212	    padding: 14px;
213	    min-width: 220px;
214	    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.6);
215	    display: none;
216	  }
217	  .vehicle-popup.show { display: block; }
218	  .popup-header {
219	    display: flex;
220	    justify-content: space-between;
221	    align-items: center;
222	    margin-bottom: 10px;
223	  }
224	  .popup-name {
225	    font-weight: 600;
226	    color: var(--accent-cyan);
227	    font-size: 14px;
228	  }
229	  .popup-close {
230	    cursor: pointer;
231	    color: var(--text-secondary);
232	    font-size: 16px;
233	    line-height: 1;
234	  }
235	  .popup-close:hover { color: var(--text-primary); }
236	  .popup-info {
237	    display: grid;
238	    grid-template-columns: 1fr 1fr;
239	    gap: 6px;
240	    font-size: 12px;
241	  }
242	  .popup-field {
243	    display: flex;
244	    flex-direction: column;
245	    gap: 2px;
246	  }
247	  .popup-field .label { color: var(--text-secondary); font-size: 10px; }
248	  .popup-field .value { color: var(--text-primary); font-weight: 500; }
249	  .popup-divider {
250	    height: 1px;
251	    background: var(--border-color);
252	    margin: 10px 0;
253	  }
254	  .popup-actions {
255	    display: flex;
256	    gap: 8px;
257	  }
258	  .popup-btn {
259	    flex: 1;
260	    padding: 6px 0;
261	    border: 1px solid var(--border-color);
262	    border-radius: 4px;
263	    background: transparent;
264	    color: var(--text-secondary);
265	    font-size: 11px;
266	    cursor: pointer;
267	    transition: all 0.2s;
268	  }
269	  .popup-btn:hover {
270	    border-color: var(--accent-cyan);
271	    color: var(--accent-cyan);
272	    background: rgba(0, 212, 255, 0.05);
273	  }
274	  .popup-btn.primary {
275	    background: rgba(0, 212, 255, 0.12);
276	    border-color: var(--accent-cyan);
277	    color: var(--accent-cyan);
278	  }
279	
280	  /* Trajectory overlay */
281	  .trajectory-overlay {
282	    position: absolute;
283	    inset: 0;
284	    z-index: 8;
285	    pointer-events: none;
286	  }
287	  .trajectory-overlay svg { width: 100%; height: 100%; }
288	
289	  /* Map controls */
290	  .map-controls {
291	    position: absolute;
292	    bottom: 16px;
293	    right: 16px;
294	    display: flex;
295	    flex-direction: column;
296	    gap: 4px;
297	    z-index: 20;
298	  }
299	  .map-ctrl-btn {
300	    width: 36px;
301	    height: 36px;
302	    background: var(--bg-panel);
303	    border: 1px solid var(--border-color);
304	    border-radius: 4px;
305	    color: var(--text-secondary);
306	    font-size: 16px;
307	    cursor: pointer;
308	    display: flex;
309	    align-items: center;
310	    justify-content: center;
311	    transition: all 0.2s;
312	  }
313	  .map-ctrl-btn:hover { color: var(--accent-cyan); border-color: var(--accent-cyan); }
314	
315	  .map-stats {
316	    position: absolute;
317	    top: 12px;
318	    left: 12px;
319	    display: flex;
320	    gap: 12px;
321	    z-index: 20;
322	  }
323	  .map-stat-chip {
324	    background: var(--bg-panel);
325	    border: 1px solid var(--border-color);
326	    border-radius: 6px;
327	    padding: 8px 14px;
328	    display: flex;
329	    align-items: center;
330	    gap: 8px;
331	  }
332	  .map-stat-chip .val { font-size: 18px; font-weight: 700; font-variant-numeric: tabular-nums; }
333	  .map-stat-chip .val.cyan { color: var(--accent-cyan); }
334	  .map-stat-chip .val.green { color: var(--accent-green); }
335	  .map-stat-chip .val.orange { color: var(--accent-orange); }
336	  .map-stat-chip .val.gray { color: rgba(120,120,140,0.7); }
337	  .map-stat-chip .lbl { font-size: 10px; color: var(--text-secondary); }
338	
339	  /* ===== Right Panel ===== */
340	  .right-panel {
341	    background: var(--bg-panel);
342	    border-left: 1px solid var(--border-color);
343	    display: flex;
344	    flex-direction: column;
345	    overflow: hidden;
346	  }
347	  .panel-header {
348	    padding: 14px 16px;
349	    border-bottom: 1px solid var(--border-color);
350	    display: flex;
351	    justify-content: space-between;
352	    align-items: center;
353	  }
354	  .panel-title {
355	    font-size: 14px;
356	    font-weight: 600;
357	  }
358	  .panel-action-btn {
359	    padding: 6px 14px;
360	    background: rgba(0, 212, 255, 0.12);
361	    border: 1px solid rgba(0, 212, 255, 0.3);
362	    border-radius: 4px;
363	    color: var(--accent-cyan);
364	    font-size: 12px;
365	    cursor: pointer;
366	    transition: all 0.2s;
367	  }
368	  .panel-action-btn:hover {
369	    background: rgba(0, 212, 255, 0.2);
370	    box-shadow: 0 0 12px rgba(0, 212, 255, 0.15);
371	  }
372	
373	  /* Gantt Chart */
374	  .gantt-container {
375	    flex: 1;
376	    overflow-y: auto;
377	    padding: 0;
378	  }
379	  .gantt-header {
380	    position: sticky;
381	    top: 0;
382	    background: var(--bg-panel);
383	    z-index: 5;
384	    border-bottom: 1px solid var(--border-color);
385	  }
386	  .gantt-time-row {
387	    display: grid;
388	    grid-template-columns: 90px 1fr;
389	  }
390	  .gantt-vehicle-label {
391	    padding: 8px 12px;
392	    font-size: 11px;
393	    color: var(--text-secondary);
394	    border-right: 1px solid var(--border-light);
395	  }
396	  .gantt-time-cells {
397	    display: grid;
398	    grid-template-columns: repeat(24, 1fr);
399	  }
400	  .gantt-time-cell {
401	    padding: 8px 0;
402	    text-align: center;
403	    font-size: 10px;
404	    color: var(--text-secondary);
405	    border-right: 1px solid var(--border-light);
406	  }
407	  .gantt-time-cell.now {
408	    color: var(--accent-cyan);
409	    font-weight: 600;
410	    background: rgba(0, 212, 255, 0.05);
411	  }
412	
413	  .gantt-row {
414	    display: grid;
415	    grid-template-columns: 90px 1fr;
416	    border-bottom: 1px solid var(--border-light);
417	    min-height: 48px;
418	  }
419	  .gantt-vehicle-info {
420	    padding: 8px 12px;
421	    display: flex;
422	    flex-direction: column;
423	    justify-content: center;
424	    gap: 2px;
425	    border-right: 1px solid var(--border-light);
426	  }
427	  .gantt-vehicle-name {
428	    font-size: 12px;
429	    font-weight: 500;
430	    color: var(--text-primary);
431	  }
432	  .gantt-vehicle-status {
433	    font-size: 10px;
434	  }
435	  .gantt-vehicle-status.running { color: var(--accent-cyan); }
436	  .gantt-vehicle-status.idle { color: var(--accent-green); }
437	  .gantt-vehicle-status.charging { color: var(--accent-orange); }
438	  .gantt-vehicle-status.offline { color: rgba(120,120,140,0.5); }
439	
440	  .gantt-track {
441	    position: relative;
442	    display: grid;
443	    grid-template-columns: repeat(24, 1fr);
444	  }
445	  .gantt-cell {
446	    border-right: 1px solid var(--border-light);
447	    min-height: 48px;
448	  }
449	
450	  /* Gantt task bars */
451	  .gantt-task {
452	    position: absolute;
453	    top: 8px;
454	    height: 32px;
455	    border-radius: 4px;
456	    cursor: pointer;
457	    display: flex;
458	    align-items: center;
459	    padding: 0 8px;
460	    font-size: 10px;
461	    font-weight: 500;
462	    overflow: hidden;
463	    white-space: nowrap;
464	    transition: box-shadow 0.2s;
465	    z-index: 3;
466	  }
467	  .gantt-task:hover {
468	    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.4);
469	    z-index: 4;
470	  }
471	  .gantt-task.running {
472	    background: linear-gradient(135deg, rgba(0, 212, 255, 0.25), rgba(0, 212, 255, 0.12));
473	    border: 1px solid rgba(0, 212, 255, 0.5);
474	    color: var(--accent-cyan);
475	  }
476	  .gantt-task.pending {
477	    background: rgba(64, 180, 255, 0.1);
478	    border: 1px solid rgba(64, 180, 255, 0.25);
479	    color: var(--accent-blue);
480	  }
481	  .gantt-task.completed {
482	    background: rgba(0, 230, 118, 0.1);
483	    border: 1px solid rgba(0, 230, 118, 0.3);
484	    color: var(--accent-green);
485	  }
486	  .gantt-task.paused {
487	    background: rgba(255, 145, 0, 0.1);
488	    border: 1px dashed rgba(255, 145, 0, 0.4);
489	    color: var(--accent-orange);
490	    opacity: 0.7;
491	  }
492	  .gantt-task.cancelled {
493	    background: rgba(120, 120, 140, 0.05);
494	    border: 1px dashed rgba(120, 120, 140, 0.2);
495	    color: rgba(120, 120, 140, 0.4);
496	    text-decoration: line-through;
497	    opacity: 0.5;
498	  }
499	
500	  /* Now indicator */
501	  .gantt-now-line {
502	    position: absolute;
503	    top: 0;
504	    bottom: 0;
505	    width: 2px;
506	    background: var(--accent-red);
507	    z-index: 6;
508	    pointer-events: none;
509	  }
510	  .gantt-now-line::before {
511	    content: "现在";
512	    position: absolute;
513	    top: -18px;
514	    left: 50%;
515	    transform: translateX(-50%);
516	    font-size: 9px;
517	    color: var(--accent-red);
518	    white-space: nowrap;
519	  }
520	
521	  /* Task Context Menu */
522	  .context-menu {
523	    position: fixed;
524	    z-index: 100;
525	    background: var(--bg-panel);
526	    border: 1px solid var(--border-color);
527	    border-radius: 6px;
528	    padding: 4px 0;
529	    min-width: 160px;
530	    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.6);
531	    display: none;
532	  }
533	  .context-menu.show { display: block; }
534	  .ctx-item {
535	    padding: 8px 14px;
536	    font-size: 12px;
537	    color: var(--text-primary);
538	    cursor: pointer;
539	    display: flex;
540	    align-items: center;
541	    gap: 8px;
542	    transition: background 0.15s;
543	  }
544	  .ctx-item:hover { background: rgba(64, 180, 255, 0.08); }
545	  .ctx-item .icon { width: 16px; text-align: center; font-size: 11px; }
546	  .ctx-item.danger { color: var(--accent-red); }
547	  .ctx-item.danger:hover { background: rgba(255, 82, 82, 0.08); }
548	  .ctx-divider { height: 1px; background: var(--border-color); margin: 4px 0; }
549	
550	  /* ===== Modal ===== */
551	  .modal-overlay {
552	    position: fixed;
553	    inset: 0;
554	    background: rgba(0, 0, 0, 0.6);
555	    z-index: 200;
556	    display: none;
557	    align-items: center;
558	    justify-content: center;
559	  }
560	  .modal-overlay.show { display: flex; }
561	  .modal {
562	    background: var(--bg-secondary);
563	    border: 1px solid var(--border-color);
564	    border-radius: 8px;
565	    width: 420px;
566	    max-width: 90vw;
567	  }
568	  .modal-header {
569	    padding: 16px 20px;
570	    border-bottom: 1px solid var(--border-color);
571	    display: flex;
572	    justify-content: space-between;
573	    align-items: center;
574	  }
575	  .modal-title { font-size: 15px; font-weight: 600; }
576	  .modal-close { cursor: pointer; color: var(--text-secondary); font-size: 18px; }
577	  .modal-close:hover { color: var(--text-primary); }
578	  .modal-body { padding: 20px; }
579	  .modal-footer {
580	    padding: 14px 20px;
581	    border-top: 1px solid var(--border-color);
582	    display: flex;
583	    justify-content: flex-end;
584	    gap: 10px;
585	  }
586	
587	  /* Form */
588	  .form-group {
589	    margin-bottom: 16px;
590	  }
591	  .form-label {
592	    display: block;
593	    font-size: 12px;
594	    color: var(--text-secondary);
595	    margin-bottom: 6px;
596	  }
597	  .form-select, .form-input {
598	    width: 100%;
599	    padding: 8px 12px;
600	    background: rgba(6, 14, 26, 0.6);
601	    border: 1px solid var(--border-color);
602	    border-radius: 4px;
603	    color: var(--text-primary);
604	    font-size: 13px;
605	    outline: none;
606	    transition: border-color 0.2s;
607	  }
608	  .form-select:focus, .form-input:focus {
609	    border-color: var(--accent-cyan);
610	  }
611	  .form-select option { background: var(--bg-secondary); }
612	  .form-row {
613	    display: grid;
614	    grid-template-columns: 1fr 1fr;
615	    gap: 12px;
616	  }
617	
618	  /* Buttons */
619	  .btn {
620	    padding: 8px 18px;
621	    border-radius: 4px;
622	    font-size: 13px;
623	    cursor: pointer;
624	    border: 1px solid transparent;
625	    transition: all 0.2s;
626	  }
627	  .btn-default {
628	    background: transparent;
629	    border-color: var(--border-color);
630	    color: var(--text-secondary);
631	  }
632	  .btn-default:hover { border-color: var(--text-secondary); color: var(--text-primary); }
633	  .btn-primary {
634	    background: rgba(0, 212, 255, 0.15);
635	    border-color: rgba(0, 212, 255, 0.4);
636	    color: var(--accent-cyan);
637	  }
638	  .btn-primary:hover { background: rgba(0, 212, 255, 0.25); }
639	  .btn-danger {
640	    background: rgba(255, 82, 82, 0.1);
641	    border-color: rgba(255, 82, 82, 0.3);
642	    color: var(--accent-red);
643	  }
644	  .btn-danger:hover { background: rgba(255, 82, 82, 0.2); }
645	
646	  /* Confirm Dialog */
647	  .confirm-text {
648	    font-size: 14px;
649	    color: var(--text-primary);
650	    margin-bottom: 8px;
651	    line-height: 1.5;
652	  }
653	  .confirm-sub {
